parameters.jsCode:
const items = $input.all();
const results = [];

for (const item of items) {
  const html = item.json.data || item.json.body || '';
  const linkRegex = /<a[^>]+href="([^"]+)"[^>]*>([^<]+)<\/a>/gi;
  let match;
  let count = 0;
  while ((match = linkRegex.exec(html)) && count < 10) {
    const title = match[2].trim();
    if (title.length > 5 && (title.includes('化妆品') || title.includes('cosmetic') || title.includes('化妆') || title.includes('原料'))) {
      results.push({
        json: {
          source: item.json.url?.includes('nmpa') ? 'nmpa' : 'chemlinked',
          title,
          url: match[1].startsWith('http') ? match[1] : `https://www.nmpa.gov.cn${match[1]}`,
          region: 'CN',
          gemini_tag: 'GEMINI_CN'
        }
      });
      count++;
    }
  }
}

return results.length ? results : [{ json: { skip: true, region: 'CN' } }];

